/* ═══════════════════════════════════════
Nord Dark (Lightweight)
       - By: jake9000
       - Description: A comprehensive but lightweight Nord Dark theme.
       - Base: Nord Theme (https://www.nordtheme.com/)
       - License: CC-0, no rights reserved
═══════════════════════════════════════ */

:root {
  /* ── Semantic Core (App Shell) ── */
  --background: #2e3440;
  --foreground: #eceff4;
  --primary: #88c0d0;
  --primary-foreground: #2e3440;
  --destructive: #bf616a;
  --destructive-foreground: #eceff4;

  /* ── Surface Colors ── */
  --card: #3b4252;
  --card-foreground: #eceff4;
  --secondary: #434c5e;
  --secondary-foreground: #d8dee9;
  --accent: #4c566a;
  --accent-foreground: #eceff4;
  --popover: #3b4252;
  --popover-foreground: #eceff4;

  /* ── Borders & Inputs ── */
  --border: #4c566a;
  --input: #3b4252;
  --ring: #88c0d0;
  --radius: 8px;

  /* ── Text ── */
  --muted: #434c5e;
  --muted-foreground: #d8dee9;

  /* ── Sidebar ── */
  --sidebar: #2e3440;
  --sidebar-foreground: #d8dee9;
  --sidebar-border: #3b4252;
  --sidebar-accent: #434c5e;
  --sidebar-accent-foreground: #88c0d0;

  /* ── UI Polish (Glass & Special Surfaces) ── */
  --panel-bg-soft: rgba(59, 66, 82, 0.78);
  --panel-bg-soft-strong: rgba(59, 66, 82, 0.82);
  --panel-border-accent: rgba(136, 192, 208, 0.25);
  --panel-border-accent-strong: rgba(136, 192, 208, 0.26);
  --panel-button-bg-strong: rgba(46, 52, 64, 0.6);
  --panel-button-hover: rgba(94, 129, 172, 0.28);
  --panel-button-hover-strong: rgba(94, 129, 172, 0.32);

  --hud-chip-bg: rgba(46, 52, 64, 0.68);
  --hud-chip-bg-hover: rgba(59, 66, 82, 0.86);
  --hud-chip-bg-active: rgba(67, 76, 94, 0.9);
  --hud-chip-border: rgba(136, 192, 208, 0.3);
  --hud-chip-border-active: rgba(143, 188, 187, 0.42);
  --hud-chip-icon: #88c0d0;

  --hud-menu-bg: rgba(46, 52, 64, 0.9);
  --hud-menu-border: rgba(136, 192, 208, 0.28);
  --hud-menu-divider: rgba(136, 192, 208, 0.16);
  --hud-menu-item-hover: rgba(94, 129, 172, 0.24);
  --hud-menu-danger-hover: rgba(191, 97, 106, 0.22);

  /* ── Glows ── */
  --glow-primary: rgba(136, 192, 208, 0.2);
  --glow-accent: rgba(143, 188, 187, 0.15);

  /* ── Y2K Palette Remapping (Catch-all for hardcoded-feeling spots) ── */
  --y2k-pink: #88c0d0;     /* Redirect pink to Frost Blue */
  --y2k-purple: #b48ead;   /* Use actual Nord Purple */
  --y2k-lavender: #b48ead;
  --y2k-blue: #81a1c1;
  --y2k-mint: #a3be8c;
  --y2k-peach: #d08770;
  --y2k-yellow: #ebcb8b;

  /* ── Hardcoded Tailwind Color Hijacking ── */
  /* Purple -> Nord Aurora Purple */
  --color-purple-300: #c29bb7;
  --color-purple-400: #b48ead;
  --color-purple-500: #a17b9b;
  --color-violet-400: #b48ead;
  --color-violet-500: #a17b9b;

  /* Emerald -> Nord Aurora Green */
  --color-emerald-300: #b1c79e;
  --color-emerald-400: #a3be8c;
  --color-emerald-500: #8ea778;

  /* Amber -> Nord Aurora Yellow/Orange */
  --color-amber-300: #f1d59f;
  --color-amber-400: #ebcb8b;
  --color-amber-500: #d08770;
  --color-orange-400: #d08770;

  /* Red -> Nord Aurora Red */
  --color-red-400: #c97981;
  --color-red-500: #bf616a;

  /* Sky/Blue -> Nord Frost Blue */
  --color-sky-300: #9ccbd8;
  --color-sky-400: #88c0d0;
  --color-sky-500: #7eb2c2;
  --color-blue-400: #81a1c1;
}

html, body {
  background: var(--background);
  color: var(--foreground);
  /* Force the font to be clean sans-serif if it was set to something else */
  font-family: "Inter", "Segoe UI", sans-serif;
}

/* ═══════════════════════════════════════
   Shared polish
═══════════════════════════════════════ */

.card, .panel, [data-slot="card"] {
  background: var(--card);
  border: 1px solid var(--border);
  box-shadow: 0 4px 14px rgba(0, 0, 0, 0.2);
}

button, .btn, [role="button"] {
  transition: transform 0.1s ease, filter 0.2s ease;
}

button:hover, .btn:hover, [role="button"]:hover {
  filter: brightness(1.1);
}

/* Custom scrollbar to match the Nord palette */
::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: #434c5e;
  border-radius: 999px;
  border: 2px solid var(--background);
}

::-webkit-scrollbar-thumb:hover {
  background: #4c566a;
}

/* ═══════════════════════════════════════
   Message Actions Overrides
═══════════════════════════════════════ */
:is(
   .mari-message-actions,
   .message-actions,
   .chat-message-actions,
   .message-toolbar,
   [data-message-actions],
   [class*="message-actions"]
) {
   display: inline-flex !important;
   align-items: center;
   justify-content: flex-start;
   flex-direction: row !important;
   align-self: flex-start;
   flex: 0 0 auto;
   width: fit-content !important;
   max-width: max-content;
   gap: 0.2rem;
   padding: 0.2rem 0.35rem;
   border-radius: 9999px;
   background: var(--panel-bg-soft) !important;
   border: 1px solid var(--panel-border-accent) !important;
   transition: background-color 140ms ease, border-color 140ms ease;
}

:is(
   .mari-message-actions,
   .message-actions,
   .chat-message-actions,
   .message-toolbar,
   [data-message-actions],
   [class*="message-actions"]
)
   > :is(button, [role="button"], a) {
   min-width: 1.75rem;
   min-height: 1.75rem;
   padding: 0.25rem;
   display: inline-flex;
   align-items: center;
   justify-content: center;
    border-radius: var(--radius);
    background: transparent !important;
   color: var(--muted-foreground) !important;
   line-height: 1;
   transition: background-color 140ms ease, color 140ms ease;
}

:is(
   .mari-message-actions,
   .message-actions,
   .chat-message-actions,
   .message-toolbar,
   [data-message-actions],
   [class*="message-actions"]
)
   > :is(button, [role="button"], a):hover,
:is(
   .mari-message-actions,
   .message-actions,
   .chat-message-actions,
   .message-toolbar,
   [data-message-actions],
   [class*="message-actions"]
)
   > :is(button, [role="button"], a):is(:focus-visible, :active) {
   background: var(--panel-button-hover) !important;
   color: var(--foreground) !important;
}

:is(
   .mari-message-actions,
   .message-actions,
   .chat-message-actions,
   .message-toolbar,
   [data-message-actions],
   [class*="message-actions"]
)
   :is(svg, .lucide, [class*="icon"]) {
   display: block;
   width: 1rem;
   height: 1rem;
}

/* Mobile refinement pass for Message action buttons */
@media (max-width: 767px) {
   :is(
      .mari-message-actions,
      .message-actions,
      .chat-message-actions,
      .message-toolbar,
      [data-message-actions],
      [class*="message-actions"]
   ) {
      max-width: calc(100vw - 1.25rem);
      width: fit-content;
      overflow-x: auto;
      overflow-y: hidden;
      -webkit-overflow-scrolling: touch;
      scrollbar-width: none;
      padding: 0.2rem 0.34rem;
      gap: 0.12rem;
   }

   :is(
      .mari-message-actions,
      .message-actions,
      .chat-message-actions,
      .message-toolbar,
      [data-message-actions],
      [class*="message-actions"]
   )::-webkit-scrollbar {
      display: none;
   }

   :is(
      .mari-message-actions,
      .message-actions,
      .chat-message-actions,
      .message-toolbar,
      [data-message-actions],
      [class*="message-actions"]
   )
      > :is(button, [role="button"], a) {
      min-width: 1.66rem;
      min-height: 1.66rem;
      padding: 0.24rem;
   }
}

/* Exact swipe pager used between message text and action buttons */
.mari-message-swipes {
   display: inline-flex !important;
   align-items: center;
   justify-content: flex-start;
   align-self: flex-start;
   flex: 0 0 auto;
   width: fit-content !important;
   max-width: max-content;
   gap: 0.3rem;
   padding: 0.2rem 0.45rem;
   min-height: 1.6rem;
   border-radius: 9999px;
   background: var(--panel-bg-soft-strong) !important;
   border: 1px solid var(--panel-border-accent-strong);
   color: var(--foreground) !important;
   font-size: 0.75rem !important;
}

.mari-message-swipes > button {
   min-width: 1.35rem;
   min-height: 1.35rem;
   padding: 0.15rem !important;
   border-radius: 9999px !important;
   background: transparent;
   transition: background-color 140ms ease;
}

.mari-message-swipes > button:hover:not(:disabled) {
   background: var(--panel-button-hover-strong) !important;
}

.mari-message-swipes > button:disabled {
   opacity: 0.45 !important;
}

/* ═══════════════════════════════════════
   Game HUD Overrides (Top Bar Widgets)
═══════════════════════════════════════ */

.rpg-hud :is(button, [role="button"])[class*="rounded-lg"][class*="backdrop-blur"][class*="bg-black/40"],
.rpg-hud > div > :is(button, [role="button"]) {
   background: var(--hud-chip-bg) !important;
   border-color: var(--hud-chip-border) !important;
   box-shadow: none !important;
}

.rpg-hud :is(button, [role="button"])[class*="rounded-lg"][class*="backdrop-blur"][class*="bg-black/40"]:hover,
.rpg-hud > div > :is(button, [role="button"]):hover {
   background: var(--hud-chip-bg-hover) !important;
}

.rpg-hud :is(button, [role="button"])[class*="rounded-lg"][class*="backdrop-blur"][class*="bg-black/60"],
.rpg-hud > div > :is(button, [role="button"])[data-state="open"] {
   background: var(--hud-chip-bg-active) !important;
   border-color: var(--hud-chip-border-active) !important;
}

.rpg-hud :is(button, [role="button"])[class*="rounded-lg"][class*="backdrop-blur"] :is(svg, .lucide),
.rpg-hud > div > :is(button, [role="button"]) :is(svg, .lucide) {
   color: var(--hud-chip-icon) !important;
}

/* Mobile refinement pass for HUD */
@media (max-width: 767px) {
   .rpg-hud {
      max-width: 100%;
      gap: 0.35rem !important;
      overflow-x: auto;
      -webkit-overflow-scrolling: touch;
      scrollbar-width: none;
      padding-bottom: 0.1rem;
   }

   .rpg-hud::-webkit-scrollbar {
      display: none;
   }

   .rpg-hud :is(button, [role="button"])[class*="rounded-lg"][class*="backdrop-blur"],
   .rpg-hud > div > :is(button, [role="button"]) {
      min-width: 2.2rem;
      min-height: 2.2rem;
      padding: 0.35rem 0.5rem !important;
      border-radius: 0.72rem;
   }

   .rpg-hud :is(button, [role="button"])[class*="rounded-lg"][class*="backdrop-blur"] :is(svg, .lucide),
   .rpg-hud > div > :is(button, [role="button"]) :is(svg, .lucide) {
      width: 0.96rem;
      height: 0.96rem;
   }
}

/* ═══════════════════════════════════════
   Game HUD Popover Menus
═══════════════════════════════════════ */

/* World state popover specifically */
.z-\[9999\].fixed.w-72.max-h-80.rounded-xl {
   background: var(--hud-menu-bg) !important;
   border-color: var(--hud-menu-border) !important;
   box-shadow:
      0 18px 44px rgba(11, 15, 22, 0.62),
      0 0 0 1px color-mix(in srgb, var(--primary) 20%, transparent) !important;
}

/* Shared widget popovers (world/player/quests/etc.) */
.z-\[9999\].rounded-xl[class*="bg-black/80"][class*="backdrop-blur-xl"] {
   background: var(--hud-menu-bg) !important;
   border-color: var(--hud-menu-border) !important;
   box-shadow:
      0 18px 44px rgba(11, 15, 22, 0.62),
      0 0 0 1px color-mix(in srgb, var(--primary) 20%, transparent) !important;
}

/* Dividers */
.z-\[9999\].fixed.w-72.max-h-80.rounded-xl [class*="border-white/5"],
.z-\[9999\].fixed.w-72.max-h-80.rounded-xl [class*="divide-white/5"],
.z-\[9999\].rounded-xl[class*="bg-black/80"][class*="backdrop-blur-xl"] :is([class*="border-white/5"], [class*="border-white/10"], [class*="ring-white/10"]),
.z-\[9999\].rounded-xl[class*="bg-black/80"][class*="backdrop-blur-xl"] [class*="divide-white/5"] {
   border-color: var(--hud-menu-divider) !important;
}

/* Muted text in menus */
.z-\[9999\].fixed.w-72.max-h-80.rounded-xl :is([class*="text-white/30"], [class*="text-white/40"], [class*="text-white/50"], [class*="text-white/60"]),
.z-\[9999\].rounded-xl[class*="bg-black/80"][class*="backdrop-blur-xl"] :is([class*="text-white/15"], [class*="text-white/20"], [class*="text-white/25"], [class*="text-white/30"], [class*="text-white/40"], [class*="text-white/50"], [class*="text-white/60"], [class*="text-white/70"], [class*="text-white/80"]) {
   color: var(--muted-foreground) !important;
}

/* Primary text in menus */
.z-\[9999\].fixed.w-72.max-h-80.rounded-xl :is([class*="text-purple-300"], [class*="text-purple-400"], [class*="text-purple-400/60"]) {
   color: var(--primary) !important;
}

/* Active/selected states in menus */
:is(.z-\[9999\].fixed.w-72.max-h-80.rounded-xl, .z-\[9999\].rounded-xl[class*="bg-black/80"][class*="backdrop-blur-xl"])
   :is([aria-selected="true"], [data-selected="true"], [data-state="active"], [data-state="checked"]) {
   background: color-mix(in srgb, var(--primary) 32%, transparent) !important; /* --selected-bg-strong */
   border-color: color-mix(in srgb, var(--primary) 52%, transparent) !important; /* --selected-border */
   color: var(--foreground) !important; /* --selected-text */
}

/* Hover states */
.z-\[9999\].fixed.w-72.max-h-80.rounded-xl [class*="bg-white/5"] {
   background: color-mix(in srgb, var(--accent) 52%, transparent) !important;
}

.z-\[9999\].fixed.w-72.max-h-80.rounded-xl button[class*="hover:bg-white/5"]:hover,
.z-\[9999\].fixed.w-72.max-h-80.rounded-xl button[class*="hover:bg-purple-500/10"]:hover,
.z-\[9999\].rounded-xl[class*="bg-black/80"][class*="backdrop-blur-xl"] button[class*="hover:bg-white/5"]:hover,
.z-\[9999\].rounded-xl[class*="bg-black/80"][class*="backdrop-blur-xl"] button[class*="hover:bg-purple-500/10"]:hover {
   background: var(--hud-menu-item-hover) !important;
}

.z-\[9999\].fixed.w-72.max-h-80.rounded-xl button[class*="hover:bg-red-500/10"]:hover,
.z-\[9999\].rounded-xl[class*="bg-black/80"][class*="backdrop-blur-xl"] button[class*="hover:text-red-400"]:hover,
.z-\[9999\].rounded-xl[class*="bg-black/80"][class*="backdrop-blur-xl"] button[class*="hover:bg-red-500/10"]:hover {
   background: var(--hud-menu-danger-hover) !important;
   color: var(--destructive) !important;
}

/* Inputs within popovers */
.z-\[9999\].rounded-xl[class*="bg-black/80"][class*="backdrop-blur-xl"] :is(input, textarea, select) {
   color: var(--foreground) !important;
   caret-color: var(--primary) !important;
}

.z-\[9999\].rounded-xl[class*="bg-black/80"][class*="backdrop-blur-xl"] :is(input, textarea, select):focus {
   border-color: #5e81ac !important; /* --input-border-contrast */
   box-shadow:
      0 0 0 1px color-mix(in srgb, #5e81ac 72%, transparent),
      0 0 0 3px color-mix(in srgb, color-mix(in srgb, var(--primary) 28%, transparent) 62%, transparent) !important;
}

.z-\[9999\].rounded-xl[class*="bg-black/80"][class*="backdrop-blur-xl"] :is(input, textarea, select)::placeholder {
   color: var(--muted-foreground) !important;
   opacity: 0.75;
}

/* ═══════════════════════════════════════
   Light Mode (Nord Snow Storm)
═══════════════════════════════════════ */
[data-theme="light"] {
  /* ── Semantic Core (App Shell) ── */
  --background: #eceff4;
  --foreground: #2e3440;
  --primary: #5e81ac; /* Darker blue for contrast */
  --primary-foreground: #eceff4;
  --destructive: #bf616a;
  --destructive-foreground: #eceff4;

  /* ── Surface Colors ── */
  --card: #e5e9f0;
  --card-foreground: #2e3440;
  --secondary: #d8dee9;
  --secondary-foreground: #3b4252;
  --accent: #d8dee9;
  --accent-foreground: #2e3440;
  --popover: #e5e9f0;
  --popover-foreground: #2e3440;

  /* ── Borders & Inputs ── */
  --border: #d8dee9;
  --input: #e5e9f0;
  --ring: #5e81ac;

  /* ── Text ── */
  --muted: #d8dee9;
  --muted-foreground: #4c566a;

  /* ── Sidebar ── */
  --sidebar: #eceff4;
  --sidebar-foreground: #3b4252;
  --sidebar-border: #d8dee9;
  --sidebar-accent: #c4cad7; /* Darkened for visible hover contrast against --secondary */
  --sidebar-accent-foreground: #5e81ac;

  /* ── UI Polish (Glass & Special Surfaces) ── */
  --panel-bg-soft: rgba(229, 233, 240, 0.78);
  --panel-bg-soft-strong: rgba(229, 233, 240, 0.82);
  --panel-border-accent: rgba(94, 129, 172, 0.25);
  --panel-border-accent-strong: rgba(94, 129, 172, 0.26);
  --panel-button-bg-strong: rgba(216, 222, 233, 0.6);
  --panel-button-hover: rgba(94, 129, 172, 0.15);
  --panel-button-hover-strong: rgba(94, 129, 172, 0.2);

  --hud-chip-bg: rgba(229, 233, 240, 0.68);
  --hud-chip-bg-hover: rgba(229, 233, 240, 0.86);
  --hud-chip-bg-active: rgba(216, 222, 233, 0.9);
  --hud-chip-border: rgba(94, 129, 172, 0.3);
  --hud-chip-border-active: rgba(94, 129, 172, 0.42);
  --hud-chip-icon: #5e81ac;

  --hud-menu-bg: rgba(236, 239, 244, 0.95);
  --hud-menu-border: rgba(94, 129, 172, 0.28);
  --hud-menu-divider: rgba(94, 129, 172, 0.16);
  --hud-menu-item-hover: rgba(94, 129, 172, 0.1);
  --hud-menu-danger-hover: rgba(191, 97, 106, 0.1);

  /* ── Glows ── */
  --glow-primary: rgba(94, 129, 172, 0.15);
  --glow-accent: rgba(129, 161, 193, 0.1);

  /* ── Y2K Palette Remapping ── */
  --y2k-pink: #5e81ac;
  --y2k-purple: #b48ead;
  --y2k-lavender: #b48ead;
  --y2k-blue: #81a1c1;
  --y2k-mint: #a3be8c;
  --y2k-peach: #d08770;
  --y2k-yellow: #ebcb8b;

  /* ── Hardcoded Tailwind Color Hijacking ── */
  --color-purple-300: #b48ead;
  --color-purple-400: #b48ead;
  --color-purple-500: #a17b9b;
  --color-violet-400: #b48ead;
  --color-violet-500: #a17b9b;

  --color-emerald-300: #a3be8c;
  --color-emerald-400: #a3be8c;
  --color-emerald-500: #8ea778;

  --color-amber-300: #ebcb8b;
  --color-amber-400: #ebcb8b;
  --color-amber-500: #d08770;
  --color-orange-400: #d08770;

  --color-red-400: #bf616a;
  --color-red-500: #bf616a;

  --color-sky-300: #81a1c1;
  --color-sky-400: #5e81ac;
  --color-sky-500: #4c566a;
  --color-blue-400: #5e81ac;
}

/* ═══════════════════════════════════════
   Right Panel / Top Bar Icon Fixes
═══════════════════════════════════════ */

/* Remove hardcoded gradient backgrounds from icons in the right panel header */
.mari-right-panel [class*="bg-gradient-to-br"] {
   background: color-mix(in srgb, var(--primary) 12%, transparent) !important;
   color: var(--primary) !important;
   box-shadow: none !important;
}

/* Fix the Top Bar active state icons */
.mari-top-bar button[class*="text-[var(--primary)]"] [class*="bg-gradient-to-r"] {
   background: var(--primary) !important;
}

/* ═══════════════════════════════════════
   Panel Navigation Buttons (Top Bar)
═══════════════════════════════════════ */

/* Nav container */
[aria-label="Panel navigation"] {
   background: var(--secondary) !important;
}

/* Default button state (inactive) */
[aria-label="Panel navigation"] button {
   color: var(--muted-foreground) !important;
   background: transparent !important;
}

/* Hover state */
[aria-label="Panel navigation"] button:hover {
   background: var(--sidebar-accent) !important;
   color: var(--sidebar-accent-foreground) !important;
}

/* Active/selected button — uses a primary tint instead of the weak accent */
[aria-label="Panel navigation"] button[class*="bg-"] {
   background: color-mix(in srgb, var(--primary) 15%, transparent) !important;
   color: var(--primary) !important;
}

/* ═══════════════════════════════════════
   Chat Sidebar
═══════════════════════════════════════ */

/* Selected item style for "CONVO" mode (left-bar indicator) */
.mari-chat-sidebar a[aria-current="page"],
.mari-chat-sidebar div[data-state="active"] {
    background: var(--card) !important;
    color: var(--sidebar-accent-foreground) !important;
    border-left: 3px solid var(--primary) !important;
    padding-left: 13px !important;
    border-radius: var(--radius);
}

/* Selected item style for "RP" mode (card-style) */
/* Use :has() to be specific and avoid breaking CONVO mode */
.mari-chat-sidebar div[role="button"][class*="bg-[var(--sidebar-accent)]"]:has(> span[style*="linear-gradient"]) {
    background: var(--card) !important;
    border: 1px solid var(--primary) !important;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2) !important;
    border-radius: var(--radius) !important;
}

/* Hide the default orange indicator on the RP card, since it now has a border */
.mari-chat-sidebar div[role="button"][class*="bg-[var(--sidebar-accent)]"]:has(> span[style*="linear-gradient"]) > span[style*="linear-gradient"] {
    display: none !important;
}

/* Generic hover for all sidebar chat items */
.mari-chat-sidebar a:hover,
.mari-chat-sidebar div[role="button"]:hover:not([class*="bg-[var(--sidebar-accent)]"]) { /* Don't apply hover to already selected RP item */
    background-color: var(--sidebar-accent) !important;
    color: var(--sidebar-accent-foreground) !important;
}

/* ═══════════════════════════════════════
   Chat Toolbar Button Overrides
═══════════════════════════════════════ */

/* Roleplay Mode Toolbar Buttons */
.mari-app :is(button, [role="button"])[class*="rounded-full"][class*="border"][class*="backdrop-blur-md"][class*="bg-foreground/5"] {
   background: var(--panel-bg-soft) !important;
   border-color: var(--panel-border-accent) !important;
   color: var(--muted-foreground) !important;
}

.mari-app :is(button, [role="button"])[class*="rounded-full"][class*="border"][class*="backdrop-blur-md"][class*="bg-foreground/5"]:hover {
   background: var(--panel-button-hover) !important;
   color: var(--foreground) !important;
}

/* Conversation Mode Toolbar Buttons */
.mari-app :is(button, [role="button"])[class*="rounded-lg"][class*="backdrop-blur-sm"][class*="bg-black/30"] {
   background: var(--panel-bg-soft) !important;
   border: 1px solid var(--panel-border-accent) !important;
   color: var(--muted-foreground) !important;
}

.mari-app :is(button, [role="button"])[class*="rounded-lg"][class*="backdrop-blur-sm"][class*="bg-black/30"]:hover {
   background: var(--panel-button-hover) !important;
   color: var(--foreground) !important;
}

/* Active/Stateful Toolbar Buttons (Summary, World Info, Author Notes) */
.mari-app :is(button, [role="button"])[class*="rounded-full"][class*="border"][class*="backdrop-blur-md"]:has(.lucide-scroll-text, .lucide-globe, .lucide-pen-line) {
   background: var(--panel-bg-soft) !important;
   border-color: var(--panel-border-accent) !important;
   color: var(--muted-foreground) !important;
}

.mari-app :is(button, [role="button"])[class*="rounded-full"][class*="border"][class*="backdrop-blur-md"]:has(.lucide-scroll-text, .lucide-globe, .lucide-pen-line):hover {
   background: var(--panel-button-hover) !important;
   color: var(--foreground) !important;
}

/* Branch Selector Button (Top Toolbar) */
.mari-app :is(button, [role="button"]):not(.mari-message-actions button):has(.lucide-git-branch) {
   background: var(--panel-bg-soft) !important;
   border: 1px solid var(--panel-border-accent) !important;
   color: var(--muted-foreground) !important;
}

.mari-app :is(button, [role="button"]):not(.mari-message-actions button):has(.lucide-git-branch):hover {
   background: var(--panel-button-hover) !important;
   color: var(--foreground) !important;
}

/* ═══════════════════════════════════════
   Chat Input Bar Overrides
═══════════════════════════════════════ */

/* The main input box container */
.mari-app .mari-chat-input-box {
   background: var(--panel-bg-soft-strong) !important;
   border-color: var(--panel-border-accent) !important;
   box-shadow: none !important;
}

.mari-app .mari-chat-input-box:focus-within,
.mari-app .mari-chat-input-box:has(textarea:not(:placeholder-shown)) {
   border-color: var(--primary) !important;
   box-shadow: 0 0 0 1px color-mix(in srgb, var(--primary) 20%, transparent) !important;
}

/* The textarea itself */
.mari-app .mari-chat-input-textarea {
   color: var(--foreground) !important;
   caret-color: var(--primary) !important;
}

.mari-app .mari-chat-input-textarea::placeholder {
   color: var(--muted-foreground) !important;
   opacity: 0.65;
}

/* Input bar icons (paperclip, emojis, send button) */
.mari-app .mari-chat-input-box > button {
   color: var(--muted-foreground) !important;
}

.mari-app .mari-chat-input-box > button:hover {
   color: var(--foreground) !important;
   background: var(--panel-button-hover) !important;
}

/* Ensure active/sending icons don't lose their intended primary color */
.mari-app .mari-chat-input-box > button.text-blue-400 {
   color: var(--primary) !important;
}

/* ═══════════════════════════════════════
   Message Bubbles Overrides
═══════════════════════════════════════ */

/* Roleplay Bubbles */
.mari-app .mari-message-bubble[class*="bg-black/40"] {
   background: var(--panel-bg-soft-strong) !important;
   border: 1px solid var(--panel-border-accent) !important;
   box-shadow: 0 4px 14px rgba(0, 0, 0, 0.2) !important;
   color: var(--foreground) !important;
}

/* Conversation/Texting Bubbles */
.mari-app .mari-message-bubble[class*="shadow-black/20"] {
   border: 1px solid var(--panel-border-accent) !important;
   box-shadow: 0 4px 14px rgba(0, 0, 0, 0.2) !important;
}

/* User Bubble in Conversation Mode */
.mari-app .texting-bubble-user {
   background: color-mix(in srgb, var(--primary) 90%, transparent) !important;
   color: var(--primary-foreground) !important;
   border: 1px solid var(--primary) !important;
}

/* Other Bubble in Conversation Mode */
.mari-app .texting-bubble-other {
   background: var(--card) !important;
   color: var(--card-foreground) !important;
   border: 1px solid var(--border) !important;
}

/* Fix "name" label above roleplay bubbles */
.mari-app .mari-message-name {
   color: var(--primary) !important;
}

/*
  [Issue #1 Fix] Override hardcoded text color on .mari-message-swipes
  in light theme by targeting all direct children for higher specificity.
*/
[data-theme="light"] .mari-message-swipes {
   background-color: var(--secondary) !important;
   border-color: var(--border) !important;
}
[data-theme="light"] .mari-message-swipes > * {
    color: var(--secondary-foreground) !important;
}

/*
  [Issue #2 Fix] Override chat input to be compliant with Nord Snowstorm.
  This targets the specific class that was overriding the intended style.
*/
[data-theme="light"] .mari-chat-input-box.bg-black\/40 {
    background: var(--secondary) !important;
}
